#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXN=1e3+5,dx[]={1,-1,0,0},dy[]={0,0,1,-1};
char corvis[MAXN][MAXN];int n,m;
queue<pair<int,int> >q;
bool BFS(int x,int y){
	q.push({x,y});
	while(true){
		pair<int,int> t=q.front();if(t==make_pair(n+10,m+10))return true;
		int X=t.first,Y=t.second;q.pop();
		for(int i=0,nowx,nowy;i<4;++i){
			nowx=X+dx[i],nowy=Y+dy[i];
			if(nowx==n+10&&nowy==m+10)return true;
			if(corvis[nowx][nowy]=='.')q.push({nowx,nowy});
			corvis[nowx][nowy]='#';
		}if(q.empty())return false;
	}
}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	memset(corvis,'#',sizeof corvis);
	scanf("%d%d",&n,&m);
	for(int i=10;i<=n;++i){
		for(int j=10;j<=m;++j){
			corvis[i][j]=getchar();
		}getchar();
	}printf("%s",((BFS(10,10))?("Yes"):("No")));
	return false;
}
